def _google_drive_file_id(url: str) -> str | None:
    """Extract a Google Drive file id from the common sharing URL formats."""
    patterns = [
        r"drive\.google\.com/file/d/([^/]+)",
        r"drive\.google\.com/open\?id=([^&]+)",
        r"drive\.google\.com/uc\?[^#]*id=([^&]+)",
    ]
    for pattern in patterns:
        match = re.search(pattern, url)
        if match:
            return match.group(1)
    return None

def video_preview_url(url: str) -> str:
    """Return a browser-friendly preview URL for Drive videos."""
    file_id = _google_drive_file_id(url)
    if file_id:
        return f"https://drive.google.com/file/d/{file_id}/preview"
    return url

def video_media_url(url: str) -> str:
    """Return a URL Flet's video player can try to stream."""
    file_id = _google_drive_file_id(url)
    if file_id:
        return f"https://drive.google.com/uc?export=download&id={file_id}"
    return url

def drive_image_url(url: str, width: int = 1200) -> str:
    """Return a Google Drive image URL that Flet can load directly."""
    file_id = _google_drive_file_id(url)
    if file_id:
        return f"https://drive.google.com/thumbnail?id={file_id}&sz=w{width}"
    return url

def corrosion_video_source() -> str:
    if not CORROSION_LOCAL_VIDEO:
        return ""
    local_path = os.path.join(os.path.dirname(__file__), CORROSION_LOCAL_VIDEO)
    if os.path.exists(local_path):
        return os.path.abspath(local_path)
    return ""

def open_url(page, url: str):
    if page is not None and url:
        asyncio.create_task(page.launch_url(url))

def open_local_or_remote_video(page, remote_url: str):
    source = corrosion_video_source()
    if source:
        open_url(page, source)
        return
    open_url(page, video_preview_url(remote_url))

def video_panel(url: str, page: ft.Page | None = None):
    """Return a video player for a local file or a Drive URL; fallback to a preview link.

    If a local file named by `CORROSION_LOCAL_VIDEO` exists and `flet_video` is
    available, play it. Otherwise, if `flet_video` is available and a remote
    URL is provided, attempt to stream the media URL. If `flet_video` is not
    installed, show a hint and a clickable preview link when `page` is given.
    """
    source = corrosion_video_source()
    # Play local file if present
    if source and fv is not None:
        return ft.Container(
            content=fv.Video(
                playlist=[fv.VideoMedia(source)],
                width=400, height=230,
                autoplay=False, show_controls=True,
                fit="contain",
            ),
            border_radius=10,
            clip_behavior=ft.ClipBehavior.ANTI_ALIAS,
        )

    # Try to stream from remote URL when flet-video is installed
    if fv is not None and url:
        media = video_media_url(url)
        return ft.Container(
            content=fv.Video(
                playlist=[fv.VideoMedia(media)],
                width=400, height=230,
                autoplay=False, show_controls=True,
                fit="contain",
            ),
            border_radius=10,
            clip_behavior=ft.ClipBehavior.ANTI_ALIAS,
        )

    # Fallback UI: show a message and a preview/open button when possible
    preview = video_preview_url(url) if url else ""
    message = f"Put {CORROSION_LOCAL_VIDEO} in the same folder as this Python file."
    if fv is None:
        message = "Install flet-video to embed remote videos: python -m pip install flet-video"

    children = [
        ft.Icon(ft.Icons.PLAY_CIRCLE, size=54, color=ACCENT_LIGHT),
        ft.Text("Video file needed", size=16, color=WHITE, weight=ft.FontWeight.BOLD),
        ft.Text(message, size=12, color=LIGHT, text_align=ft.TextAlign.CENTER),
    ]

    if preview:
        if page is not None:
            children.append(ft.Container(height=6))
            children.append(ft.ElevatedButton(
                "Open preview",
                on_click=lambda e, url=preview: asyncio.create_task(page.launch_url(url)),
                bgcolor=ACCENT, color=WHITE,
                elevation=0,
            ))
        else:
            children.append(ft.Container(height=6))
            children.append(ft.Text(preview, size=12, color=ACCENT_LIGHT))

    return ft.Container(
        content=ft.Column(children,
                          horizontal_alignment=ft.CrossAxisAlignment.CENTER,
                          alignment=ft.MainAxisAlignment.CENTER,
                          spacing=8),
        width=400, height=230,
        bgcolor="#1A2744",
        border=_border_all(1, BORDER_COL),
        border_radius=10,
        clip_behavior=ft.ClipBehavior.ANTI_ALIAS,
    )

