def zoom_image_dialog(page, title, b64, width=420, height=280):
    print(f"zoom_image_dialog called: {title} (b64 len={len(b64) if b64 else 0})")
    def _close(e):
        page.dialog = None
        page.update()

    dialog = ft.AlertDialog(
        modal=True,
        title=ft.Text(title, color=WHITE, weight=ft.FontWeight.BOLD),
        content=ft.Container(
            content=ft.Image(
                src=_b64_to_tmp(b64),
                width=width,
                height=height,
                fit="contain",
            ),
            border_radius=12,
            padding=0,
        ),
        actions=[
            ft.TextButton("Close", on_click=_close),
        ],
    )
    page.dialog = dialog
    page.update()


def zoom_local_image_dialog(page, title, path, width=420, height=280):
    print(f"zoom_local_image_dialog called: {title} -> {path}")
    dialog = ft.AlertDialog(
        modal=True,
        title=ft.Text(title, color=WHITE, weight=ft.FontWeight.BOLD),
        content=ft.Container(
            content=ft.Image(
                src=_local_file_to_tmp(path),
                width=width,
                height=height,
                fit="contain",
            ),
            border_radius=12,
            padding=0,
        ),
        actions=[
            # we'll set a proper close handler below to support current flet API
            ft.TextButton("Close", on_click=None),
        ],
    )
    def _close_local(e):
        page.dialog = None
        page.update()
    # replace the placeholder None handler with our local closer
    dialog.actions[0].on_click = _close_local
    page.dialog = dialog
    page.update()


def image_entry_src(item, width=1200):
    path = item.get("path", "") if item else ""
    if path and os.path.exists(path):
        return _local_file_to_tmp(path)
    url = item.get("url", "") if item else ""
    return drive_image_url(url, width) if url else ""


