def semester_file_viewer(item, on_back, on_home, on_toggle_fullscreen, fullscreen=False):
    title = item.get("title", "Semester File") if item else "Semester File"
    kind = item.get("kind", "File") if item else "File"
    relative_path = item.get("path", "") if item else ""
    path = _project_file_path(relative_path)
    ext = os.path.splitext(path)[1].lower()

    viewer_height = 620 if fullscreen else 430
    viewer_width = 1100 if fullscreen else 760

    if not os.path.exists(path):
        body = ft.Container(
            content=ft.Text("This file was not found in the project folder.",
                            size=13, color=LIGHT),
            padding=18,
            border_radius=12,
            bgcolor="#0F1D31",
            border=_border_all(1, BORDER_COL),
        )
    elif ext == ".py":
        with open(path, "r", encoding="utf-8", errors="replace") as source:
            code = source.read()
        body = ft.Container(
            content=ft.Text(code, size=11, color=LIGHT, font_family="Consolas"),
            width=viewer_width,
            height=viewer_height,
            padding=16,
            border_radius=12,
            bgcolor="#08111F",
            border=_border_all(1, BORDER_COL),
        )
    elif ext == ".pdf":
        rendered_pages = _render_pdf_pages(path)
        if rendered_pages:
            body = ft.Column([
                ft.Container(
                    content=ft.Image(src=image, width=viewer_width, fit="contain"),
                    width=viewer_width,
                    padding=10,
                    border_radius=12,
                    bgcolor="#F8FAFC",
                    border=_border_all(1, BORDER_COL),
                )
                for image in rendered_pages
            ], spacing=14)
        else:
            body = ft.Container(
                content=ft.Column([
                    ft.Icon(ft.Icons.PICTURE_AS_PDF, size=54, color=ACCENT_LIGHT),
                    ft.Text("PDF preview is inside the portfolio, but the PDF renderer is not available.",
                            size=13, color=LIGHT, text_align=ft.TextAlign.CENTER),
                    ft.Text(os.path.basename(path), size=12, color=DIM,
                            text_align=ft.TextAlign.CENTER),
                ], spacing=8, horizontal_alignment=ft.CrossAxisAlignment.CENTER),
                width=viewer_width,
                height=viewer_height,
                alignment=ft.Alignment(0, 0),
                border_radius=12,
                bgcolor="#0F1D31",
                border=_border_all(1, BORDER_COL),
            )
    elif os.path.isdir(path):
        file_count = sum(len(files) for _, _, files in os.walk(path))
        body = ft.Container(
            content=ft.Column([
                ft.Icon(ft.Icons.APPS, size=58, color=ACCENT_LIGHT),
                ft.Text("Project folder selected", size=16, color=WHITE,
                        weight=ft.FontWeight.BOLD),
                ft.Text(
                    "This MATLAB App Designer project is included in the portfolio folder. "
                    "Open the report file for a readable preview of the app documentation.",
                    size=13, color=LIGHT, text_align=ft.TextAlign.CENTER),
                ft.Text(f"{os.path.basename(path)} - {file_count} files",
                        size=12, color=DIM, text_align=ft.TextAlign.CENTER),
            ], spacing=8, horizontal_alignment=ft.CrossAxisAlignment.CENTER),
            width=viewer_width,
            height=viewer_height,
            alignment=ft.Alignment(0, 0),
            border_radius=12,
            bgcolor="#0F1D31",
            border=_border_all(1, BORDER_COL),
        )
    else:
        size_kb = os.path.getsize(path) / 1024
        body = ft.Container(
            content=ft.Column([
                ft.Icon(ft.Icons.APPS, size=58, color=ACCENT_LIGHT),
                ft.Text("App package selected", size=16, color=WHITE,
                        weight=ft.FontWeight.BOLD),
                ft.Text(
                    "This file stays inside the portfolio as a semester-work item. "
                    "Use the report file for a readable preview of the app documentation.",
                    size=13, color=LIGHT, text_align=ft.TextAlign.CENTER),
                ft.Text(f"{os.path.basename(path)} - {size_kb:.1f} KB",
                        size=12, color=DIM, text_align=ft.TextAlign.CENTER),
            ], spacing=8, horizontal_alignment=ft.CrossAxisAlignment.CENTER),
            width=viewer_width,
            height=viewer_height,
            alignment=ft.Alignment(0, 0),
            border_radius=12,
            bgcolor="#0F1D31",
            border=_border_all(1, BORDER_COL),
        )

    return ft.Column([
        ft.Row([
            back_button("Back", on_back),
            ft.Container(expand=True),
            file_action_button(
                ft.Icons.FULLSCREEN_EXIT if fullscreen else ft.Icons.OPEN_IN_FULL,
                "Exit Full Screen" if fullscreen else "Full Screen",
                on_toggle_fullscreen,
            ),
            back_button("Home", on_home),
        ], alignment=ft.MainAxisAlignment.END, spacing=8),
        section_heading(title),
        ft.Text(kind, size=13, color=ACCENT_LIGHT, weight=ft.FontWeight.BOLD),
        ft.Container(
            content=ft.Column([body], scroll=ft.ScrollMode.AUTO, expand=True),
            expand=fullscreen,
        ),
    ], spacing=12, scroll=ft.ScrollMode.AUTO, expand=fullscreen)


