# ══════════════════════════════════════════════════════
#  MAIN APP
# ══════════════════════════════════════════════════════
def main(page: ft.Page):
    page.title      = f"{YOUR_NAME} | Portfolio"
    page.bgcolor    = BG_WELCOME
    page.theme_mode = ft.ThemeMode.DARK
    page.padding    = 0

    current_route = {
        "v": "personal",
        "history": ["personal"],
        "file": None,
        "certificate": None,
        "image": None,
        "fullscreen": False,
    }
    sidebar_ref   = ft.Ref[ft.Column]()
    content_ref   = ft.Ref[ft.Container]()
    root_ref      = ft.Ref[ft.Stack]()
    sidebar_controls = []

    nav_defs = [
        ("personal",     ft.Icons.PERSON,            "Personal\nInfo"),
        ("projects",     ft.Icons.FOLDER,             "Projects"),
        ("achievements", ft.Icons.WORKSPACE_PREMIUM,  "Achievements"),
        ("contact",      ft.Icons.CONTACT_MAIL,       "Contact"),
    ]

    def build_content(route):
        def go_back(_):
            if len(current_route["history"]) > 1:
                previous = current_route["history"][-2]
                current_route["history"] = current_route["history"][:-1]
                navigate(previous, record=False)
            else:
                navigate("personal", record=False)

        def go_home(_):
            current_route["v"] = "personal"
            current_route["history"] = ["personal"]
            current_route["file"] = None
            current_route["certificate"] = None
            current_route["image"] = None
            current_route["fullscreen"] = False
            root_ref.current.controls = [welcome_page()]
            page.bgcolor = BG_WELCOME
            page.update()

        def open_semester_file(item):
            current_route["file"] = item
            current_route["certificate"] = None
            current_route["image"] = None
            current_route["fullscreen"] = False
            navigate("file_viewer")

        def open_certificate(cert):
            current_route["certificate"] = cert
            current_route["file"] = None
            current_route["image"] = None
            current_route["fullscreen"] = True
            navigate("certificate_viewer")

        def open_image(item):
            current_route["image"] = item
            current_route["file"] = None
            current_route["certificate"] = None
            current_route["fullscreen"] = True
            navigate("image_viewer")

        def toggle_fullscreen(_):
            current_route["fullscreen"] = not current_route["fullscreen"]
            if root_ref.current is not None:
                root_ref.current.controls = [main_layout()]
            page.update()

        if route == "personal":     return personal_info_page(go_back, go_home)
        if route == "projects":     return projects_page(go_back, go_home, page, open_semester_file, open_image)
        if route == "file_viewer":
            return semester_file_viewer(
                current_route["file"],
                go_back,
                go_home,
                toggle_fullscreen,
                current_route["fullscreen"],
            )
        if route == "certificate_viewer":
            return certificate_fullscreen_viewer(
                current_route["certificate"],
                go_back,
                go_home,
            )
        if route == "image_viewer":
            return local_image_fullscreen_viewer(
                current_route["image"],
                go_back,
                go_home,
            )
        if route == "achievements": return achievements_page(go_back, go_home, page, open_certificate)
        if route == "contact":      return contact_page(go_back, go_home, page)
        return personal_info_page(go_back, go_home)

    def navigate(route, record=True):
        if route != "file_viewer":
            current_route["file"] = None
        if route != "certificate_viewer":
            current_route["certificate"] = None
        if route != "image_viewer":
            current_route["image"] = None
        if route not in ("file_viewer", "certificate_viewer", "image_viewer"):
            current_route["fullscreen"] = False
        if route != current_route["v"]:
            current_route["v"] = route
            if record:
                current_route["history"].append(route)
                if len(current_route["history"]) > 10:
                    current_route["history"] = current_route["history"][-10:]
        refresh_sidebar()
        if content_ref.current is not None:
            content_ref.current.content = build_content(route)
        page.update()

    def refresh_sidebar():
        nonlocal sidebar_controls
        sidebar_controls = [
            sidebar_btn(icon, label, route,
                        active=(current_route["v"] == route),
                        on_click=navigate)
            for route, icon, label in nav_defs
        ]
        if sidebar_ref.current is not None:
            sidebar_ref.current.controls = sidebar_controls

    def enter_portfolio(_):
        if root_ref.current is not None:
            root_ref.current.controls = [main_layout()]
        page.bgcolor = BG_MAIN
        page.update()

    # ── Welcome page ──────────────────────────────────────────────────────────
    def welcome_page():
        profile = ft.Container(
            content=ft.Image(src_base64=IMG_PROFILE, width=150, height=150,
                             fit="cover"),
            width=150, height=150, border_radius=75,
            clip_behavior=ft.ClipBehavior.ANTI_ALIAS,
            border=_border_all(3, ACCENT),
        )

        enter_btn = ft.Container(
            content=ft.ElevatedButton(
                "Enter Portfolio  →",
                on_click=enter_portfolio,
                bgcolor=ACCENT,
                color=WHITE,
                elevation=0,
                style=ft.ButtonStyle(
                    padding=ft.padding.Padding(left=36, right=36, top=16, bottom=16),
                    overlay_color=ACCENT_LIGHT,
                ),
            ),
            border_radius=12,
            shadow=[ft.BoxShadow(blur_radius=30, color="#501E90FF",
                                 spread_radius=2, offset=ft.Offset(0, 4))],
        )

        return ft.Container(
            expand=True,
            gradient=ft.LinearGradient(
                begin=ft.Alignment(0, -1), end=ft.Alignment(0, 1),
                colors=[BG_WELCOME, "#0D2B4E", "#1565C0"],
            ),
            content=ft.Column([
                profile,
                ft.Container(height=12),
                ft.Text(YOUR_NAME, size=32, weight=ft.FontWeight.BOLD,
                        color=WHITE, text_align=ft.TextAlign.CENTER),
                ft.Container(height=28),
                enter_btn,
            ],
            horizontal_alignment=ft.CrossAxisAlignment.CENTER,
            alignment=ft.MainAxisAlignment.CENTER,
            expand=True),
        )

    # ── Main layout ───────────────────────────────────────────────────────────
    def main_layout():
        sidebar = ft.Container(
            width=88,
            bgcolor=SIDEBAR_BG,
            border=ft.Border(right=ft.BorderSide(1, BORDER_COL)),
            padding=ft.padding.Padding(left=6, right=6, top=20, bottom=20),
            content=ft.Column(
                ref=sidebar_ref,
                controls=sidebar_controls,
                spacing=10,
                horizontal_alignment=ft.CrossAxisAlignment.CENTER,
                scroll=ft.ScrollMode.AUTO,
            ),
        )

        content_area = ft.Container(
            ref=content_ref,
            expand=True,
            padding=ft.padding.Padding(left=20, right=20, top=20, bottom=20),
            bgcolor=BG_MAIN,
            content=build_content(current_route["v"]),
        )

        refresh_sidebar()

        layout_controls = []
        if not current_route["fullscreen"]:
            layout_controls.append(sidebar)
        layout_controls.append(
            ft.Container(
                expand=True,
                content=ft.Column([
                    ft.Container(
                        expand=True,
                        content=ft.Column(
                            [content_area],
                            scroll=ft.ScrollMode.AUTO,
                            expand=True,
                        ),
                    ),
                ], expand=True),
            ),
        )

        return ft.Row(layout_controls, expand=True, spacing=0)

    root = ft.Stack(ref=root_ref, controls=[welcome_page()], expand=True)
    page.add(ft.Container(content=root, expand=True))


ft.app(main)
